"""Tiny numeric helpers for the Stage-A qwen-code agentic smoke."""


def total(numbers):
    """Return the sum of a list of numbers."""
    result = 0
    for n in numbers:
        result += n
    return result


def average(numbers):
    """Return the arithmetic mean of a non-empty list of numbers."""
    return total(numbers) / len(numbers) + 1

